mapper.select:
SELECT h.hid, h.title, h.type, t.tname as typeName, h.page_views as pageViews,
       h.like_count as likeCount, h.comment_count as commentCount,
       TIMESTAMPDIFF(HOUR, h.published_time, NOW()) as pastHours,
       h.publisher, u.username as author, h.status, h.is_top as isTop,
       h.cover_image_url as coverImage,
h.created_time as createdTime, h.updated_time as updatedTime, h.published_time as publishedTime,
h.source_type as sourceType, h.source_id as sourceId, h.lang,
h.mongodb_collection as mongodbCollection, h.mongodb_document_id as mongodbDocumentId
FROM headlines h
LEFT JOIN news_types t ON h.type = t.tid
LEFT JOIN users u ON h.publisher = u.id
WHERE h.status = 1

    AND h.type = #{type}


    AND h.title LIKE CONCAT('%', #{keyWords}, '%')


    AND h.publisher = #{publisher}


    AND h.lang = #{lang}


    AND h.source_type = #{sourceType}


    AND h.source_id = #{sourceId}

ORDER BY h.is_top DESC, h.published_time DESC
LIMIT #{pageSize} OFFSET #{pageNum}

SELECT COUNT(*)
FROM headlines h
WHERE h.status = 1

    AND h.type = #{type}


    AND h.title LIKE CONCAT('%', #{keyWords}, '%')


    AND h.publisher = #{publisher}


    AND h.lang = #{lang}


    AND h.source_type = #{sourceType}


    AND h.source_id = #{sourceId}
